985	/* Emit code for a procedure call.
986	 * CALL node: nd_name = procedure name, nd_left = first arg (linked via nd_next).
987	 * COR24 calling convention:
988	 *   - Evaluate arguments left-to-right
989	 *   - Push arguments right-to-left onto stack
990	 *   - Call via jal r1,(r2)
991	 *   - Clean up stack after return (add sp, arg_count*3)
992	 *   - Return value in r0 */
993	
994	void cg_call(int node) {
995	    int nargs;
996	    int arg;
997	    int i;
998	    int cleanup;
999	
1000	    if (node == NODE_NULL) return;
1001	
1002	    nargs = cg_count_args(nd_left[node]);
1003	
1004	    if (nargs == 0) {
1005	        /* No arguments: just call */
1006	        emit_str(EMIT_INDENT);
1007	        emit_str("la      r2,_");
1008	        emit_line(nd_name[node]);
1009	        emit_instr("jal     r1,(r2)");
1010	    } else {
1011	        /* Evaluate args L-to-R, store in R-to-L stack order.
1012	         * Pre-allocate space, then store each at the correct offset
1013	         * so first arg ends up at lowest address (closest to sp).
1014	         * Callee sees fp+9 = first arg, fp+12 = second, etc. */
1015	        cleanup = nargs * 3;
1016	        emit_str(EMIT_INDENT);
1017	        emit_str("lc      r2,");
1018	        emit_int(cleanup);
1019	        emit_nl();
1020	        emit_instr("sub     sp,r2");
1021	
1022	        /* Evaluate each arg L-to-R and store at sp + i*3.
1023	         * arg1 at sp+0 -> callee fp+9 (first param)
1024	         * arg2 at sp+3 -> callee fp+12 (second param) */
1025	        arg = nd_left[node];
1026	        i = 0;
1027	        while (arg != NODE_NULL) {
1028	            cg_expr(arg);
1029	            emit_str(EMIT_INDENT);
1030	            emit_str("sw      r0,");
1031	            emit_int(i * 3);
1032	            emit_line("(sp)");
1033	            i = i + 1;
1034	            arg = nd_next[arg];
1035	        }
1036	
1037	        /* Call the procedure */
1038	        emit_str(EMIT_INDENT);
1039	        emit_str("la      r2,_");
1040	        emit_line(nd_name[node]);
1041	        emit_instr("jal     r1,(r2)");
1042	
1043	        /* Clean up args from stack */
1044	        emit_str(EMIT_INDENT);
1045	        emit_str("lc      r2,");
1046	        emit_int(cleanup);
1047	        emit_nl();
1048	        emit_instr("add     sp,r2");
1049	    }
1050	}
