1149	/* DO I = start TO end; ... END; codegen.
1150	 * Lowers to: I = start; WHILE (I <= end) { body; I = I + 1; }
1151	 * AST: nd_name = loop var, nd_left = start, nd_ival = end expr, nd_right = body */
1152	void cg_do_count(int node) {
1153	    int lbl_top;
1154	    int lbl_end;
1155	
1156	    lbl_top = emit_new_label();
1157	    lbl_end = emit_new_label();
1158	
1159	    /* I = start: evaluate start expr into r0, store to loop var */
1160	    cg_expr(nd_left[node]);
1161	    cg_store_var(node);  /* nd_name[node] = loop var name */
1162	
1163	    /* Loop header label */
1164	    emit_label(lbl_top);
1165	
1166	    /* Compare: load I into r0, save, eval end into r0, then compare */
1167	    cg_load_var(node);       /* r0 = I */
1168	    emit_instr("push    r0");
1169	    cg_expr(nd_ival[node]);  /* r0 = end */
1170	    emit_instr("mov     r1,r0");  /* r1 = end */
1171	    emit_instr("pop     r0");     /* r0 = I */
1172	
1173	    /* Branch to end if I > end (i.e., end < I) */
1174	    emit_instr("cls     r1,r0");  /* carry if end < I */
1175	    emit_str(EMIT_INDENT);
1176	    emit_str("bc      ");
1177	    emit_label_ref(lbl_end);
1178	    emit_nl();
1179	
1180	    /* Loop body */
1181	    cg_stmt(nd_right[node]);
1182	
1183	    /* Increment: I = I + 1 */
1184	    cg_load_var(node);
1185	    emit_instr("lc      r1,1");
1186	    emit_instr("add     r0,r1");
1187	    cg_store_var(node);
1188	
1189	    /* Branch back to header */
1190	    emit_str(EMIT_INDENT);
1191	    emit_str("jmp     ");
1192	    emit_label_ref(lbl_top);
1193	    emit_nl();
1194	
1195	    /* End label */
1196	    emit_label(lbl_end);
1197	}
