1201	/* Emit code for a single statement node */
1202	void cg_stmt(int node) {
1203	    if (node == NODE_NULL) return;
1204	
1205	    if (nd_kind[node] == NODE_ASSIGN) {
1206	        cg_assign(node);
1207	    } else if (nd_kind[node] == NODE_RETURN) {
1208	        /* Evaluate return expression into r0 (if present) */
1209	        if (nd_left[node] != NODE_NULL) {
1210	            cg_expr(nd_left[node]);
1211	        }
1212	        /* Epilogue emitted by caller at procedure end.
1213	         * For early returns, emit epilogue inline. */
1214	        emit_epilogue();
1215	    } else if (nd_kind[node] == NODE_CALL) {
1216	        /* Bare CALL statement (result in r0 discarded) */
1217	        cg_call(node);
1218	    } else if (nd_kind[node] == NODE_BLOCK) {
1219	        cg_block(node);
1220	    } else if (nd_kind[node] == NODE_IF) {
1221	        /* IF/THEN/ELSE: evaluate condition, branch on false */
1222	        cg_if(node);
1223	    } else if (nd_kind[node] == NODE_DO_WHILE) {
1224	        /* DO WHILE: loop with condition at top */
1225	        cg_do_while(node);
1226	    } else if (nd_kind[node] == NODE_DO_COUNT) {
1227	        /* DO I = start TO end: counted loop */
1228	        cg_do_count(node);
1229	    } else if (nd_kind[node] == NODE_DCL) {
1230	        /* Local DCL: no code emission needed (handled by layout) */
1231	    } else {
1232	        cg_error("unsupported statement kind");
1233	        emit_comment("ERROR: unsupported statement");
1234	        emit_str(EMIT_INDENT);
1235	        emit_str("; kind=");
1236	        emit_int(nd_kind[node]);
1237	        emit_nl();
