1255	/* Emit code for a complete procedure.
1256	 * proc_node is a NODE_PROC with:
1257	 *   nd_name  = procedure name
1258	 *   nd_left  = first parameter (linked via nd_next)
1259	 *   nd_right = body (BLOCK node)
1260	 *   nd_ival  = option flags (OPT_FREESTANDING, OPT_NAKED, OPT_LEAF)
1261	 *   nd_stor  = return type
1262	 *
1263	 * Layout must be performed first via layout_proc(). */
1264	
1265	void cg_proc(int proc_node) {
1266	    int opts;
1267	    int frame_sz;
1268	    int has_body;
1269	    int body;
1270	
1271	    if (proc_node == NODE_NULL) return;
1272	    if (nd_kind[proc_node] != NODE_PROC) {
1273	        cg_error("expected PROC node");
1274	        return;
1275	    }
1276	
1277	    opts = nd_ival[proc_node];
1278	    body = nd_right[proc_node];
1279	
1280	    /* Ensure we're in .text section */
1281	    emit_text_section();
1282	
1283	    /* Emit .globl directive and label */
1284	    if (nd_name[proc_node]) {
1285	        emit_global(nd_name[proc_node]);
1286	        emit_named_label(nd_name[proc_node]);
1287	    }
1288	
1289	    /* NAKED procedures: no prologue/epilogue, body is raw */
1290	    if (opts & 2) {
1291	        /* OPT_NAKED */
1292	        emit_comment("NAKED procedure -- no prologue/epilogue");
1293	        cg_block(body);
1294	        return;
1295	    }
1296	
1297	    /* Standard prologue: push fp, push r2, push r1, mov fp,sp */
1298	    emit_prologue();
1299	
1300	    /* Allocate stack space for locals (sub sp, frame_size) */
1301	    frame_sz = layout_frame_size;
1302	    if (frame_sz > 0) {
1303	        if (frame_sz >= -128 && frame_sz <= 127) {
1304	            emit_str(EMIT_INDENT);
1305	            emit_str("lc      r0,");
1306	            emit_int(frame_sz);
1307	            emit_nl();
1308	        } else {
1309	            emit_str(EMIT_INDENT);
1310	            emit_str("la      r0,");
1311	            emit_int(frame_sz);
1312	            emit_nl();
1313	        }
1314	        emit_instr("sub     sp,r0");
1315	    }
1316	
1317	    /* Emit body statements */
1318	    cg_block(body);
1319	
1320	    /* Standard epilogue: mov sp,fp, pop r1, pop r2, pop fp, jmp (r1) */
1321	    emit_epilogue();
1322	}
