1	/* types.h -- Type representation and checking for PL/SW compiler */
2	/* Builds on TYPE_ constants defined in ast.h */
3	
4	#ifndef TYPES_H
5	#define TYPES_H
6	
7	#include "ast.h"
8	
9	/* --- Type width --- */
10	
11	/* Return the width in bytes for a simple type tag */
12	int type_width(int t) {
13	    if (t == TYPE_BIT)   return 1;
14	    if (t == TYPE_INT8)  return 1;
15	    if (t == TYPE_BYTE)  return 1;
16	    if (t == TYPE_CHAR)  return 1;
17	    if (t == TYPE_INT16) return 2;
18	    if (t == TYPE_WORD)  return 3;
19	    if (t == TYPE_INT24) return 3;
20	    if (t == TYPE_PTR)   return 3;
21	    return 0;  /* TYPE_NONE, TYPE_ARRAY, TYPE_RECORD -- no simple width */
22	}
23	
24	/* --- Type classification --- */
25	
26	int type_is_integer(int t) {
27	    if (t == TYPE_INT8)  return 1;
28	    if (t == TYPE_INT16) return 1;
29	    if (t == TYPE_INT24) return 1;
30	    if (t == TYPE_BYTE)  return 1;
31	    if (t == TYPE_CHAR)  return 1;
32	    if (t == TYPE_BIT)   return 1;
33	    if (t == TYPE_WORD)  return 1;
34	    return 0;
35	}
36	
37	int type_is_signed(int t) {
38	    if (t == TYPE_INT8)  return 1;
39	    if (t == TYPE_INT16) return 1;
40	    if (t == TYPE_INT24) return 1;
41	    return 0;
42	}
43	
44	int type_is_ptr(int t) {
45	    return t == TYPE_PTR;
46	}
47	
48	int type_is_scalar(int t) {
49	    return type_is_integer(t) || type_is_ptr(t);
50	}
51	
52	/* --- Type descriptor table for compound types --- */
53	/* Stores extra metadata for ARRAY and RECORD types */
54	
55	#define TDESC_MAX 64
56	
57	/* Descriptor kind */
58	#define TDESC_NONE   0
59	#define TDESC_ARRAY  1
60	#define TDESC_RECORD 2
61	
62	int td_kind[TDESC_MAX];       /* TDESC_ARRAY or TDESC_RECORD */
63	int td_elem_type[TDESC_MAX];  /* ARRAY: element type tag */
64	int td_count[TDESC_MAX];      /* ARRAY: element count; RECORD: field count */
65	int td_size[TDESC_MAX];       /* total size in bytes */
66	
67	/* Record field info -- parallel arrays, max 16 fields per record */
68	#define TDESC_FIELD_MAX 16
69	#define TDESC_FIELDS_TOTAL 1024  /* 64 descriptors * 16 fields */
70	
71	char *td_fname[TDESC_FIELDS_TOTAL];   /* field name */
72	int   td_ftype[TDESC_FIELDS_TOTAL];   /* field type tag */
73	int   td_fwidth[TDESC_FIELDS_TOTAL];  /* field width in bytes */
74	int   td_foffset[TDESC_FIELDS_TOTAL]; /* field offset from record start */
75	
76	int td_count_alloc;  /* number of allocated descriptors */
77	
78	void types_init(void) {
79	    td_count_alloc = 0;
80	}
81	
82	/* Allocate a new type descriptor. Returns index or -1. */
83	int td_alloc(int kind) {
84	    if (td_count_alloc >= TDESC_MAX) return -1;
85	    int i = td_count_alloc;
86	    td_count_alloc = td_count_alloc + 1;
87	    td_kind[i] = kind;
88	    td_elem_type[i] = TYPE_NONE;
89	    td_count[i] = 0;
90	    td_size[i] = 0;
91	    return i;
92	}
93	
94	/* Create an array type descriptor.
95	   Returns descriptor index or -1. */
96	int td_make_array(int elem_type, int elem_count) {
97	    int i = td_alloc(TDESC_ARRAY);
98	    if (i < 0) return -1;
99	    td_elem_type[i] = elem_type;
100	    td_count[i] = elem_count;
101	    td_size[i] = type_width(elem_type) * elem_count;
102	    return i;
103	}
104	
105	/* Create a record type descriptor from DCL AST node.
106	   Walks the children (field DCL nodes) and computes offsets.
107	   Returns descriptor index or -1. */
108	int td_make_record(int dcl_node) {
109	    int i;
110	    int fbase;
111	    int fcount;
112	    int offset;
113	    int child;
114	    int fw;
115	
116	    i = td_alloc(TDESC_RECORD);
117	    if (i < 0) return -1;
118	
119	    fbase = i * TDESC_FIELD_MAX;
120	    fcount = 0;
121	    offset = 0;
122	
123	    /* Walk child fields of the record DCL node */
124	    child = nd_left[dcl_node];
125	    while (child != NODE_NULL && fcount < TDESC_FIELD_MAX) {
126	        fw = type_width(nd_type[child]);
127	        /* Arrays: width = element_width * dimension */
128	        if (nd_ival[child] > 0) {
129	            fw = fw * nd_ival[child];
130	        }
131	        if (fw == 0) fw = 3;  /* default to 24-bit for untyped fields */
132	
133	        td_fname[fbase + fcount] = nd_name[child];
134	        td_ftype[fbase + fcount] = nd_type[child];
135	        td_fwidth[fbase + fcount] = fw;
136	        td_foffset[fbase + fcount] = offset;
137	
138	        offset = offset + fw;
139	        fcount = fcount + 1;
140	        child = nd_next[child];
141	    }
142	
143	    td_count[i] = fcount;
144	    td_size[i] = offset;
145	    return i;
146	}
147	
148	/* Look up a field in a record descriptor by name.
149	   Returns the field index (within descriptor) or -1 if not found. */
150	int td_field_lookup(int desc, char *name) {
151	    int fbase;
152	    int fc;
153	    int j;
154	
155	    if (desc < 0 || desc >= td_count_alloc) return -1;
156	    if (td_kind[desc] != TDESC_RECORD) return -1;
157	
158	    fbase = desc * TDESC_FIELD_MAX;
159	    fc = td_count[desc];
160	    j = 0;
161	    while (j < fc) {
162	        if (str_eq_nocase(td_fname[fbase + j], name)) {
163	            return j;
164	        }
165	        j = j + 1;
166	    }
167	    return -1;
168	}
169	
170	/* Get field offset within a record descriptor */
171	int td_field_offset(int desc, int field_idx) {
172	    int fbase;
173	    if (desc < 0 || field_idx < 0) return 0;
174	    fbase = desc * TDESC_FIELD_MAX;
175	    return td_foffset[fbase + field_idx];
176	}
177	
178	/* Get field type within a record descriptor */
179	int td_field_type(int desc, int field_idx) {
180	    int fbase;
181	    if (desc < 0 || field_idx < 0) return TYPE_NONE;
182	    fbase = desc * TDESC_FIELD_MAX;
183	    return td_ftype[fbase + field_idx];
184	}
185	
186	/* Get field width within a record descriptor */
187	int td_field_width(int desc, int field_idx) {
188	    int fbase;
189	    if (desc < 0 || field_idx < 0) return 0;
190	    fbase = desc * TDESC_FIELD_MAX;
191	    return td_fwidth[fbase + field_idx];
192	}
193	
194	/* --- Type compatibility checking --- */
195	
196	/* Type checking error state */
197	int tc_err;
198	char *tc_errmsg;
199	
200	void tc_init(void) {
201	    tc_err = 0;
202	    tc_errmsg = 0;
203	}
204	
205	void tc_error(char *msg) {
206	    tc_err = 1;
207	    tc_errmsg = msg;
208	}
209	
210	/* Check if value of type 'from' can be assigned to variable of type 'to'.
211	   Returns 1 if compatible, 0 if not (and sets tc_err). */
212	int type_compat_assign(int from, int to) {
213	    /* Same type is always compatible */
214	    if (from == to) return 1;
215	
216	    /* Any integer type can be assigned to any other integer type
217	       (implicit widening/narrowing, PL/I style) */
218	    if (type_is_integer(from) && type_is_integer(to)) return 1;
219	
220	    /* Integer can be assigned to PTR (address literal) */
221	    if (type_is_integer(from) && to == TYPE_PTR) return 1;
222	
223	    /* PTR can be assigned to integer (cast) */
224	    if (from == TYPE_PTR && type_is_integer(to)) return 1;
225	
226	    /* PTR to PTR */
227	    if (from == TYPE_PTR && to == TYPE_PTR) return 1;
228	
229	    /* NONE type -- untyped, compatible with anything */
230	    if (from == TYPE_NONE || to == TYPE_NONE) return 1;
231	
232	    tc_error("incompatible types in assignment");
233	    return 0;
234	}
235	
236	/* Determine the result type of a binary operation.
237	   Returns the result type tag, or TYPE_NONE on error. */
238	int type_binop_result(int op, int left, int right) {
239	    /* Comparison operators always produce INT24 (boolean result) */
240	    if (op == TOK_EQ || op == TOK_NE ||
241	        op == TOK_LT || op == TOK_GT ||
242	        op == TOK_LE || op == TOK_GE) {
243	        /* Both sides must be scalar */
244	        if (!type_is_scalar(left) || !type_is_scalar(right)) {
245	            tc_error("comparison requires scalar operands");
