    emit_init();
    emit_str(EMIT_INDENT);
    emit_line(".text");
    emit_in_data = 0;
    emit_nl();
    emit_str(EMIT_INDENT);
    emit_line(".globl  _start");
    emit_line("_start:");
    emit_instr2("la", "r0", "_main");
    emit_instr2("jal", "r1", "(r0)");
    emit_line("_halt:");
    emit_instr("bra     _halt");
    emit_nl();
    emit_global("main");
    emit_named_label("main");
    emit_prologue();
    /* load 42 into r0 */
    int ret_label = emit_new_label();
    emit_instr2("lc", "r0", "42");
