    uart_putstr("  BYTE width=");
    print_int(layout_dcl_width(n));
    uart_putchar(10);

    arena_init();
    ast_init();
    parse_init("DCL P PTR;");
    n = parse_dcl();
    uart_putstr("  PTR width=");
    print_int(layout_dcl_width(n));
    uart_putchar(10);

