    n = parse_dcl();
    uart_putstr("  CHAR width=");
    print_int(layout_dcl_width(n));
    uart_putchar(10);

    arena_init();
    ast_init();
    parse_init("DCL W WORD;");
    n = parse_dcl();
    uart_putstr("  WORD width=");
    print_int(layout_dcl_width(n));
    uart_putchar(10);

    /* Test 2: array widths */
