            errs = errs + 1;
        }
        /* No jmp to label (no else means no jump-over-else) */
        if (str_find(out, "jmp     L")) {
            uart_puts("  FAIL: unexpected jmp in if/then (no else)");
            errs = errs + 1;
        }
    }

    /* Test 2: IF/THEN/ELSE */
