    parse_init("PROC NESTED(N INT(24)); DCL I INT(24); DCL J INT(24); I = 0; DO WHILE (I < N); J = 0; DO WHILE (J < N); J = J + 1; END; I = I + 1; END; END;");
    prog = parse_program();
